    if (strncat(cmd_buffer, " netmask ", buffer_size - strlen(cmd_buffer) - 1) == NULL) {
        return -1;
    }

    /* Add netmask */
    if (strncat(cmd_buffer, netmask, buffer_size - strlen(cmd_buffer) - 1) == NULL) {
        return -1;
    }

    /* Third part: " gateway " */
    if (strncat(cmd_buffer, " gateway ", buffer_size - strlen(cmd_buffer) - 1) == NULL) {
        return -1;
    }

    /* Add gateway */
    if (strncat(cmd_buffer, gateway, buffer_size - strlen(cmd_buffer) - 1) == NULL) {
        return -1;
    }

    return 0;
}
